import{E as e,F as t,N as n,T as r,a as i,b as a,g as o,j as s,m as c,r as l,w as u,y as d}from"./index-ChqmyjCp.js";var f={class:`content-main`},p={class:`content-wrapper`},m={class:`sidebar-container`},h={class:`sticky-toc`},g={class:`toc-list`},_=[`onClick`],v={class:`content-area`},y={class:`manual-container`},b={id:`faq`,class:`manual-section`},x={class:`faq-list`},S={class:`faq-question`},C={class:`faq-answer`},w=l({__name:`UserManualView`,setup(l){let w=i(),T=s(JSON.parse(localStorage.getItem(`user`)||`{}`)),E=s(`intro`),D=[{id:`intro`,label:`1. Introduction`},{id:`getting-started`,label:`2. Getting Started`},{id:`dashboard`,label:`3. Dashboard Overview`},{id:`submissions`,label:`4. Submitting Forms`},{id:`viewing`,label:`5. Viewing Submissions`},{id:`mandates`,label:`6. GAD Mandates Management`},{id:`budget`,label:`7. Budget Monitoring`},{id:`reports`,label:`8. Reports`},{id:`faq`,label:`9. Frequently Asked Questions`},{id:`support`,label:`10. Technical Support`}],O=[{q:`What should I do if I encounter an error while submitting a form?`,a:`Check that all required fields are filled out correctly. Ensure file sizes are within limits (10MB for activity designs, 15MB per file for reports). If the issue persists, contact technical support.`},{q:`Can I edit a submission after it has been submitted?`,a:`As a monitoring user, you cannot edit submissions. If changes are needed, please contact the GAD Office administrator.`},{q:`How do I view the full content of uploaded files?`,a:`Click the "Preview" button on any document to view it in the browser. Download buttons are not available for staff users.`},{q:`What does the "Archive" section contain?`,a:`The archive contains cancelled activity designs and completed activities (both designs and accomplishment reports). You can filter by status and type.`},{q:`How do I interpret the Activity Rating?`,a:`The activity rating uses a 0-100% scale with corresponding descriptors (Excellent, Very Satisfactory, Satisfactory, Needs Improvement, Unsatisfactory, Canceled). Refer to the rating table in the accomplishment report form.`}],k=e=>{E.value=e;let t=document.getElementById(e);if(t){let e=t.getBoundingClientRect().top+window.scrollY+-96;window.scrollTo({top:e,behavior:`smooth`})}};return u(()=>{(!T.value.id||T.value.role!==`gad_staff`)&&w.push(`/login`)}),(i,s)=>(r(),d(c,null,[o(`main`,f,[o(`div`,p,[o(`div`,m,[o(`div`,h,[s[0]||=o(`h3`,{class:`toc-title`},` Table of Contents `,-1),o(`ul`,g,[(r(),d(c,null,e(D,e=>o(`li`,{key:e.id},[o(`button`,{onClick:t=>k(e.id),class:n([`sidebar-nav-item`,{"active-nav-item":E.value===e.id}])},t(e.label),11,_)])),64))])])]),o(`div`,v,[o(`div`,y,[s[2]||=a(`<div id="intro" class="manual-section" data-v-98b950b0><h1 class="page-title" data-v-98b950b0>User Manual</h1><p class="intro-text" data-v-98b950b0> Welcome to the Benguet State University Gender and Development Activities Management System (GAD-AMS) User Manual. This guide will help you navigate and use the system effectively as a GAD Staff user. </p></div><div id="getting-started" class="manual-section" data-v-98b950b0><h2 class="section-title" data-v-98b950b0>2. Getting Started</h2><div class="subsection" data-v-98b950b0><div data-v-98b950b0><h3 class="subsection-title" data-v-98b950b0>2.1 Logging In</h3><p class="subsection-text" data-v-98b950b0> Access the system via your web browser using the provided URL. Enter your username and password credentials provided by the system administrator. </p></div><div data-v-98b950b0><h3 class="subsection-title" data-v-98b950b0>2.2 Navigating the Dashboard</h3><p class="subsection-text" data-v-98b950b0> After logging in, you will be directed to the Staff Dashboard. The left sidebar contains all main navigation menus including Dashboard, GAD Programs, Mandates Management, Budget Monitoring, and Reports. </p></div></div></div><div id="dashboard" class="manual-section" data-v-98b950b0><h2 class="section-title" data-v-98b950b0>3. Dashboard Overview</h2><p class="subsection-text" data-v-98b950b0> The dashboard provides a quick overview of key metrics and pending activities: </p><ul class="styled-list" data-v-98b950b0><li data-v-98b950b0><strong data-v-98b950b0>Pending Activities</strong> - Shows number of activity designs awaiting review</li><li data-v-98b950b0><strong data-v-98b950b0>Activity Designs</strong> - Count of submitted activity designs</li><li data-v-98b950b0><strong data-v-98b950b0>Accomplishment Reports</strong> - Count of submitted accomplishment reports</li><li data-v-98b950b0><strong data-v-98b950b0>GAD Budget</strong> - Displays current budget allocation and utilization</li><li data-v-98b950b0><strong data-v-98b950b0>Calendar Widget</strong> - Shows upcoming deadlines and scheduled activities</li><li data-v-98b950b0><strong data-v-98b950b0>Recent Activity Logs</strong> - Tracks recent system activities</li></ul></div><div id="submissions" class="manual-section" data-v-98b950b0><h2 class="section-title" data-v-98b950b0>4. Submitting Forms</h2><div class="subsection" data-v-98b950b0><h3 class="subsection-title" data-v-98b950b0>4.1 Activity Design Submission</h3><ol class="styled-list numeric" data-v-98b950b0><li data-v-98b950b0>Click the &quot;New Submission&quot; button on the sidebar or the floating action button</li><li data-v-98b950b0>Select &quot;Activity Design&quot; from the options</li><li data-v-98b950b0>Fill out the form with: <ul class="nested-list" data-v-98b950b0><li data-v-98b950b0>Nature of Transaction (Employee, INSET, Extension, or Student Activity)</li><li data-v-98b950b0>Activity Title</li><li data-v-98b950b0>Start and End Dates</li><li data-v-98b950b0>Start and End Times</li><li data-v-98b950b0>Venue</li><li data-v-98b950b0>Target Participants (max 6 digits)</li><li data-v-98b950b0>Proposed Budget</li><li data-v-98b950b0>Upload Activity Design file (PDF/DOCX)</li><li data-v-98b950b0>Proponent Information</li></ul></li><li data-v-98b950b0>Click &quot;Submit Activity Design&quot; to complete the submission</li></ol></div><div class="subsection" data-v-98b950b0><h3 class="subsection-title" data-v-98b950b0>4.2 Accomplishment Report Submission</h3><ol class="styled-list numeric" data-v-98b950b0><li data-v-98b950b0>Click the &quot;New Submission&quot; button on the sidebar or the floating action button</li><li data-v-98b950b0>Select &quot;Accomplishment Report&quot; from the options</li><li data-v-98b950b0>Fill out the form with: <ul class="nested-list" data-v-98b950b0><li data-v-98b950b0>Activity Title</li><li data-v-98b950b0>Control Number (select from approved activity designs dropdown)</li><li data-v-98b950b0>Start and End Dates</li><li data-v-98b950b0>Start and End Times</li><li data-v-98b950b0>Venue</li><li data-v-98b950b0>Number of Attendees (max 6 digits)</li><li data-v-98b950b0>Male/Female Participant Breakdown</li><li data-v-98b950b0>Activity Rating (0-100% with criteria table)</li><li data-v-98b950b0>Upload Report &amp; Attachments (multiple files accepted)</li><li data-v-98b950b0>Proponent Information</li></ul></li><li data-v-98b950b0>Click &quot;Submit Accomplishment Report&quot; to complete the submission</li></ol></div></div><div id="viewing" class="manual-section" data-v-98b950b0><h2 class="section-title" data-v-98b950b0>5. Viewing Submissions</h2><p class="subsection-text" data-v-98b950b0> As a GAD Staff user, you have monitoring access to view all submissions: </p><ul class="styled-list" data-v-98b950b0><li data-v-98b950b0><span class="bold-text" data-v-98b950b0>Activity Designs:</span> Navigate to &quot;Submitted Activity Designs&quot; from the sidebar to view all submitted designs. Click &quot;View&quot; on any row to see the complete details.</li><li data-v-98b950b0><span class="bold-text" data-v-98b950b0>Accomplishment Reports:</span> Navigate to &quot;Submitted Accomplishment Reports&quot; to view all reports. Click &quot;View&quot; to see the complete report with ratings and attachments.</li><li data-v-98b950b0><span class="bold-text" data-v-98b950b0>Filters:</span> Use the filter bar to sort by status, form type, office, or search by title/control number.</li></ul><div class="note-box" data-v-98b950b0> Note: Staff users can only view documents (preview only). No download buttons are available for uploaded files. </div></div><div id="mandates" class="manual-section" data-v-98b950b0><h2 class="section-title" data-v-98b950b0>6. GAD Mandates Management</h2><p class="subsection-text" data-v-98b950b0>This section displays all GAD mandates where the GAD Office is the responsible unit:</p><ul class="styled-list" data-v-98b950b0><li data-v-98b950b0>View the complete list of 22 GAD Office mandates</li><li data-v-98b950b0>Filter mandates by status (In Progress, Completed, Upcoming)</li><li data-v-98b950b0>Search for specific mandates by title</li><li data-v-98b950b0>Access the GAD Plan &amp; Budget document (PDF viewer)</li><li data-v-98b950b0>Assign mandates to accomplishment reports</li></ul></div><div id="budget" class="manual-section" data-v-98b950b0><h2 class="section-title" data-v-98b950b0>7. Budget Monitoring</h2><p class="subsection-text" data-v-98b950b0>The budget monitoring page provides:</p><ul class="styled-list" data-v-98b950b0><li data-v-98b950b0>Total GAD Budget overview</li><li data-v-98b950b0>GAD Office Budget breakdown by category</li><li data-v-98b950b0>Balance available for implementation</li><li data-v-98b950b0>Mandate-based budget utilization tracking with progress bars</li><li data-v-98b950b0>Recent budget utilization logs</li><li data-v-98b950b0>Expense category split summary</li></ul></div><div id="reports" class="manual-section" data-v-98b950b0><h2 class="section-title" data-v-98b950b0>8. Reports</h2><p class="subsection-text" data-v-98b950b0>Generate and view annual reports:</p><ul class="styled-list" data-v-98b950b0><li data-v-98b950b0><span class="bold-text" data-v-98b950b0>Annual Report:</span> Comprehensive report of GAD accomplishments with sex-disaggregated data</li><li data-v-98b950b0><span class="bold-text" data-v-98b950b0>GAD Plan &amp; Budget:</span> View the GPB document in table or PDF format</li><li data-v-98b950b0><span class="bold-text" data-v-98b950b0>Export to Excel:</span> Download report data for offline analysis</li><li data-v-98b950b0><span class="bold-text" data-v-98b950b0>Year Selection:</span> Switch between different fiscal years (2024-2026)</li></ul></div>`,8),o(`div`,b,[s[1]||=o(`h2`,{class:`section-title`},`9. Frequently Asked Questions`,-1),o(`div`,x,[(r(),d(c,null,e(O,(e,n)=>o(`div`,{class:`faq-item`,key:n},[o(`h3`,S,`Q: `+t(e.q),1),o(`p`,C,`A: `+t(e.a),1)])),64))])]),s[3]||=a(`<div id="support" class="manual-section" data-v-98b950b0><h2 class="section-title" data-v-98b950b0>10. Technical Support</h2><p class="subsection-text" data-v-98b950b0>For technical assistance, bug reports, or system inquiries, please contact:</p><div class="support-box" data-v-98b950b0><p class="support-title" data-v-98b950b0>GAD-AMS System Administrator</p><p class="support-text" data-v-98b950b0>Gender and Development Office</p><p class="support-text" data-v-98b950b0>Benguet State University</p><p class="support-email" data-v-98b950b0>Email: gad.ims@bsu.edu.ph</p><p class="support-text" data-v-98b950b0>Tel: (074) 422-2401 loc 123</p></div><p class="version-info" data-v-98b950b0>System Version: 1.0 | Last Updated: January 2026</p></div>`,1)])])])]),s[4]||=o(`footer`,{class:`footer-watermark`},[o(`p`,{class:`watermark-text`},` Benguet State University - Gender and Development Activities Management System | GAD-AMS v1.0 `)],-1)],64))}},[[`__scopeId`,`data-v-98b950b0`]]);export{w as default};